{% set igst_account_head = [] -%}
{% set tax_accounts = [] %}
{% set grand_total = {"qty":0.0, "amount":0.0, "cgst_amt":0.0, "sgst_amt":0.0, "igst_amt":0.0} %}
{%- for tax in doc.taxes -%}
{% if 'CGST' in tax.account_head -%}
{% set _ = cgst_account_head.append(tax.account_head) %}
{% set _ = cgst_rate.append(tax.rate) %}
{% set _ = tax_accounts.append(tax.description) %}
{%- endif -%}
{% if 'SGST' in tax.account_head -%}
{% set _ = sgst_account_head.append(tax.account_head) %}
{% set _ = sgst_rate.append(tax.rate) %}
{% set _ = tax_accounts.append(tax.description) %}
{%- endif -%}
{% if 'IGST' in tax.account_head -%}
{% set _ = igst_account_head.append(tax.account_head) %}
{% set _ = igst_rate.append(tax.rate) %}
{% set _ = tax_accounts.append(tax.description) %}
{%- endif -%}
{%- endfor -%}

{%- with discount_data = {'amt':0, 'rate':0, 'is_excl':False}, extra_data = {"is_b2b":False} -%}
{%- set _ = extra_data.update({"is_b2b": doc.get("customer_group", "Individual") != "Individual"}) -%}

<section class="content">
  {% set company_doc = frappe.get_doc("Company", doc.company) %}

  <table class="table" style="width: 100%; border-collapse: collapse; border: 1px solid #000 !important;">
    <thead>
      <!-- ROW 1: BRANDING (Repeats on every page) -->
      <tr>
        <th colspan="12" style="padding: 10px; border-bottom: 1px solid #000;">
          <table style="width: 100%; border: none !important;">
            <tr>
              <td style="width: 40%; vertical-align: middle; border: none !important; text-align: left;">
                <img src="{{ company_doc.logo_for_printing or company_doc.company_logo }}" style="max-height: 80px;">
              </td>
              <td style="width: 60%; text-align: left; vertical-align: top; border: none !important;">
                <p class="fs-small fw-bold fst-upper m-0" style="font-size: 14px !important;">{{ doc.company }}</p>
                <p class="fs-xsmall m-0"><b>GSTIN:</b> {{ doc.company_gstin or company_doc.gstin or "-" }}</p>
                <p class="fs-xsmall m-0"><b>PAN NO.:</b> {{ company_doc.pan or "-" }}</p>
                <p class="fs-xsmall m-0"><b>Address:</b> 
  {% if doc.company_address %}
    {% set c_addr = frappe.get_doc("Address", doc.company_address) %}
    {% set line1 = c_addr.address_line1.strip(" ,") if c_addr.address_line1 else "" %}
    {% set line2 = c_addr.address_line2.strip(" ,") if c_addr.address_line2 else "" %}
    {% set city  = c_addr.city.strip(" ,") if c_addr.city else "" %}
    {% set state = c_addr.state.strip(" ,") if c_addr.state else "" %}
    {{ [line1, line2, city, state] | select | join(', ') }}
  {% else %}
    {{ doc.company_address_display|striptags }}
  {% endif %}
</p>
                <div style="margin-top: 5px;">
                   <span class="fs-xmini"><span style="color:#230bb3;">&#9990;</span> {{ company_doc.phone_no or "" }}</span> &nbsp;&nbsp;
                   <span class="fs-xmini"><span style="color:#230bb3;">&#9993;</span> {{ company_doc.email or "" }}</span>
                </div>
              </td>
            </tr>
          </table>
        </th>
      </tr>

      <!-- ROW 2: PACKING SLIP TITLE (Repeats on every page) -->
      <!-- ROW 2: PACKING SLIP TITLE -->
<tr>
  <th colspan="12" style="text-align: center; border-bottom: 1.5px solid #000; padding: 8px; background-color: #fff !important;">
     <p style="font-size: 16px !important; font-weight: bold; margin: 0; text-align: center !important; width: 100%; display: block; letter-spacing: 2px;">PACKING SLIP</p>
  </th>
</tr>

      <!-- ROW 3: BILL TO & INFO (Repeats on every page) -->
      <!-- ROW 3: BILL TO & INFO -->
<!-- ROW 3: BILL TO & INFO -->
<tr>
  <td colspan="12" style="padding: 0; border-bottom: 1px solid #000; background-color: #fff !important;">
    <!-- table-layout: fixed ensures the 50/50 split is honored perfectly -->
    <table style="width: 100%; border-collapse: collapse; border: none !important; table-layout: fixed;">
      <tr>
        <!-- Left Column: Set to 50% for center line -->
        <td style="width: 50%; padding: 10px; vertical-align: top; border-right: 1px solid #000; border-top: none !important; border-bottom: none !important; border-left: none !important; text-align: left;">
           <table style="width: 100%; border: none !important;">
             <tr>
               <!-- FIXED: width changed from 50% to 60px to pull address to the left -->
               <td style="width: 60px; vertical-align: top; border: none !important; padding: 0 !important; font-weight: bold; font-size: 13px;">Bill To:</td>
               <td style="vertical-align: top; border: none !important; padding: 0 !important; text-align: left;">
                  <div style="font-size: 11px; color: #444; margin: 0 0 2px 0; line-height: 1.3;">
                    {% if doc.customer_address %}
                      {% set addr = frappe.get_doc("Address", doc.customer_address) %}
                      {{ addr.address_line1 or '' }}{% if addr.address_line2 %}, {{ addr.address_line2 }}{% endif %}<br>
                      {{ addr.city or '' }}{% if addr.state %}, {{ addr.state }}{% endif %}
                    {% endif %}
                  </div>
                  <p style="font-weight: bold; font-size: 12px; margin-top: 5px; margin-bottom: 0;">Phone: {{ frappe.db.get_value("Address", {'name': doc.customer_address}, "phone") or '' }}</p>
               </td>
             </tr>
           </table>
        </td>
        <!-- Right Column: Set to 50% for center line -->
        <td style="width: 50%; padding: 10px; vertical-align: top; border: none !important; text-align: left;">
            <p style="font-size: 12px; margin: 0; font-weight: normal;"><b>Invoice No:</b> {{ doc.name }}</p>
            <p style="font-size: 12px; margin: 8px 0 0 0; font-weight: normal;"><b>Invoice Date:</b> {{ doc.get_formatted("posting_date") }}</p>
        </td>
      </tr>
    </table>
  </td>
</tr>

      <!-- ROW 4: ITEM TABLE HEADERS (Repeats on every page) -->
      <tr style="background-color: #fff;">
        <th style="width: 4%; border: 1px solid #000; padding: 5px; font-size: 10px;">S.N.</th>
        <th style="width: 11%; border: 1px solid #000; padding: 5px; font-size: 10px;">Serial No./BARCODE</th>
        <th style="width: 7%; border: 1px solid #000; padding: 5px; font-size: 10px;">Image</th>
        <th style="width: 7%; border: 1px solid #000; padding: 5px; font-size: 10px;">HSN Code</th>
        <th style="width: 10%; border: 1px solid #000; padding: 5px; font-size: 10px;">STYLE NO</th>
        <th style="width: 14%; border: 1px solid #000; padding: 5px; font-size: 10px;">Department</th>
        <th style="width: 8%; border: 1px solid #000; padding: 5px; font-size: 10px;">FABRIC</th>
        <th style="width: 8%; border: 1px solid #000; padding: 5px; font-size: 10px;">COLOR</th>
        <th style="width: 9%; border: 1px solid #000; padding: 5px; font-size: 10px;">SIZE</th>
        <th style="width: 4%; border: 1px solid #000; padding: 5px; font-size: 10px; text-align: center;">QTY</th>
        <th style="width: 8%; border: 1px solid #000; padding: 5px; font-size: 10px; text-align: center;">MRP</th>
        <th style="width: 10%; border: 1px solid #000; padding: 5px; font-size: 10px; text-align: right;">Gross Amount</th>
      </tr>
    </thead>
    <tbody>
      {% set table_totals = {'qty': 0, 'gross_amt': 0} %}
      {% for item in doc.items %}
      {% set item_master = frappe.get_doc("Item", item.item_code) %}
      <tr>
        <td class="text-center" style="border: 1px solid #000; vertical-align: middle;"><p class="fs-mini m-0">{{ loop.index }}</p></td>
        <td class="text-center" style="border: 1px solid #000; vertical-align: middle;"><p class="fs-mini m-0">{{ item.serial_no.split("\n")[0] if item.serial_no else "-" }}</p></td>
        <td class="text-center" style="border: 1px solid #000; vertical-align: middle; padding: 5px !important;">
            {% if item_master.image %}
                <img src="{{ item_master.image }}" style="max-height:50px; max-width:70px;">
            {% else %}
                <span class="fs-xmini">No Image</span>
            {% endif %}
        </td>
        <td class="text-center" style="border: 1px solid #000; vertical-align: middle;"><p class="fs-mini m-0">{{ item.gst_hsn_code or "-" }}</p></td>
        <td class="text-center" style="border: 1px solid #000; vertical-align: middle;"><p class="fs-mini m-0">{{ item.item_code }}</p></td>
        <td style="border: 1px solid #000; vertical-align: middle;"><p class="fs-mini m-0">{{ item_master.custom_group_collection or "-" }}</p></td>
        <td style="border: 1px solid #000; vertical-align: middle;"><p class="fs-mini m-0">{{ item_master.custom_top_fabrics or "-" }}</p></td>
        <td style="border: 1px solid #000; vertical-align: middle;"><p class="fs-mini m-0">{{ item_master.custom_colour_name or "-" }}</p></td>
        <td style="border: 1px solid #000; vertical-align: middle;"><p class="fs-mini m-0">{{ item_master.custom_size or "-" }}</p></td>
        <td class="text-center" style="border: 1px solid #000; vertical-align: middle;"><p class="fs-mini m-0">{{ item.qty | int }}</p></td>
        <td class="text-center" style="border: 1px solid #000; vertical-align: middle;"><p class="fs-mini m-0">{{ frappe.utils.fmt_money(item.price_list_rate, currency=doc.currency) }}</p></td>
        <td class="text-right" style="border: 1px solid #000; vertical-align: middle;"><p class="fs-mini m-0">{{ frappe.utils.fmt_money(item.amount, currency=doc.currency) }}</p></td>
      </tr>
      {% set _ = table_totals.update({'qty': table_totals.qty + item.qty, 'gross_amt': table_totals.gross_amt + item.amount}) %}
      {% endfor %}

      <!-- TOTAL ROW -->
      <tr style="font-weight: bold; background-color: #fafafa;">
        <td colspan="9" class="text-right" style="border: 1px solid #000; padding: 5px;"><p class="fs-small fw-bold m-0">TOTAL</p></td>
        <td class="text-center" style="border: 1px solid #000; padding: 5px;"><p class="fs-small fw-bold m-0">{{ table_totals.qty | int }}</p></td>
        <td style="border: 1px solid #000; padding: 5px;"></td>
        <td class="text-right" style="border: 1px solid #000; padding: 5px;"><p class="fs-small fw-bold m-0">{{ frappe.utils.fmt_money(table_totals.gross_amt, currency=doc.currency) }}</p></td>
      </tr>
    </tbody>
  </table>
</section>
{%- endwith -%}
